return "";

/*
* Calc to get the IN_INVOICE_VENDOR selected label
* By Adriana Centellas
*/
const vendor = this.PM_VENDOR_SOURCE.find(item => item.ID === this.IN_INVOICE_VENDOR);

const label = vendor ? vendor.LABEL : "";

return label;

if(this.IN_SAVE_SUBMIT === "SUBMIT" || this.IN_SAVE_SUBMIT == null){
    return true;
}
return false;

/**
 * Pre Tax Calculation
 * 
 * by Favio Mollinedo
 */
//let invTtoal    = (this.IN_INVOICE_TOTAL > 0)? this.IN_INVOICE_TOTAL.toFixed(2): 0;
let invTtoal    = this.IN_INVOICE_TOTAL.toFixed(2);
//let invTaxTotal = (this.IN_INVOICE_TAX_TOTAL > 0)?this.IN_INVOICE_TAX_TOTAL.toFixed(2): 0;
let invTaxTotal = (this.IN_INVOICE_TAX_TOTAL == null || this.IN_INVOICE_TAX_TOTAL == '') ? '0.00' : this.IN_INVOICE_TAX_TOTAL;
invTaxTotal = parseFloat(invTaxTotal).toFixed(2)
let preTaxTotal = invTtoal - invTaxTotal;
return preTaxTotal.toLocaleString("en-US", { minimumFractionDigits: 2, maximumFractionDigits: 2 });

/*
 * by Adriana Centellas
 */

/**
 * Validates that the input length does not exceed 60 characters.
 * @param {string} input - The user input to validate.
 * @return {boolean} Returns true if the input length is 60 or fewer characters, otherwise false.
 */
function validateInput(input) {
    //Convert to string always to prevent issue with only numbers
    input = String(input);
    const isValid = input.length <= 60; // Check if input length is within the limit
    return isValid;
}

return validateInput(this.IN_INVOICE_TRANS_COMMENTS);

let addressValue = this.vendorInformation[0].EXPENSE_VENDOR_ADDRESS ?? '';
if (addressValue === null || addressValue == 'null') {
    addressValue = '';
}
return addressValue;

let tempVendor = this.IN_INVOICE_VENDOR_LABEL.replace("|", " |");
let caseNumber = (this._request.case_number != undefined) ? this._request.case_number : '';
return caseNumber + ' - ' + tempVendor +  ' - ' + this.IN_INVOICE_NUMBER + ' - ' + this.IN_INVOICE_DATE;

/** 
 * Modified by Telmo Chiri
*/
let userNode = this._user;
// Delete extra nodes
delete userNode.meta;
delete userNode.schedule;

return userNode;

let action = this.IN_INVOICE_ADD_VENDOR;
let vendorMessage = this.IN_REQUEST_NEW_VENDOR_MESSAGE;
let actionPopUp = this.IN_POPUP_SEND;
let copyMessage   = vendorMessage.replace(/\n/g, "<--br /-->");
copyMessage = copyMessage.replace(/["']/g, "")
return copyMessage;

let visible = false;
const regex = /^[a-zA-Z0-9\s'.,;:!?()\-#%@\$]+$/;
if (this.IN_REQUEST_NEW_VENDOR_MESSAGE != "" &&
    regex.test(this.IN_REQUEST_NEW_VENDOR_MESSAGE)) {
    visible = true;
}
return visible;

custom_css:
[selector='button-align'] div {
  align-content: center;
  text-align: center;
}

[selector='button_send'] div {
  margin-top: 15px !important;
}

button[name="buttonCancelPopUp"] {
  float: right;
}

.modal-footer {
  display: none !important;
}

[selector='azure_result']{
    display: flex;
    margin-bottom: -30%;
    position: relative;
    z-index: 1;
}
@media (max-width: 1540px) {
    [selector='azure_result']{
        display: flex;
        margin-bottom: -25%;
        position: relative;
        z-index: 1;
    }
}
[selector="buttons-bar"] button {
    width: 100% !important;
}
[selector='required'] label::before {
  content: "*  ";
  color: #DC3646;
}
[selector='required'] input {
  border: 1.5px solid #DC3646;
}
.button-as-links {
    background: none;
    color: #711426;
    border: none;
    padding: 0;
    text-decoration: underline;
    cursor: pointer;
    font: inherit;
}
